import React from 'react';
import ProjectCard from './ProjectCard';
import { Project } from '../types';

const placeholder = (n: number) => `https://via.placeholder.com/1200x675?text=Project+${n}`;

const placeholderProjects: Project[] = [
  { id: 'p1', title: "Little Simz 'Flood'", description: 'Short film / Selected Work', thumbnail: placeholder(1), link: '#', category: 'Selected Work', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p2', title: "Epiclesis 'Short Film'", description: 'Short film / Narrative', thumbnail: placeholder(2), link: '#', category: 'Narrative', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p3', title: "Moeder 'Short Film'", description: 'Short film / Narrative', thumbnail: placeholder(3), link: '#', category: 'Narrative', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p4', title: "HP 'The Wrong Kind of Busy'", description: 'Commercial', thumbnail: placeholder(4), link: '#', category: 'Commercials', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p5', title: "Young Fathers 'Mr. Martyr'", description: 'Music video', thumbnail: placeholder(5), link: '#', category: 'Music Videos', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p6', title: "NBA 'Don't Miss a Thing'", description: 'Commercial / Sports', thumbnail: placeholder(6), link: '#', category: 'Commercials', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p7', title: "Beyond the Endless Light", description: 'Selected Work', thumbnail: placeholder(7), link: '#', category: 'Selected Work', createdAt: new Date(), updatedAt: new Date() },
  { id: 'p8', title: "House of Diligence 'Documentary'", description: 'Documentary', thumbnail: placeholder(8), link: '#', category: 'Format Agnostic', createdAt: new Date(), updatedAt: new Date() },
];

interface ProjectListProps {
  selectedCategory?: string;
}

const ProjectList: React.FC<ProjectListProps> = ({ selectedCategory = 'All Projects' }) => {
  const filtered = selectedCategory === 'All Projects'
    ? placeholderProjects
    : placeholderProjects.filter(p => p.category === selectedCategory);

  return (
    <section className="project-grid">
      {filtered.map((project, index) => (
        <div className="project-card" key={project.id}>
          <ProjectCard project={project as Project} index={index} />
        </div>
      ))}
    </section>
  );
};

export default ProjectList;
